mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT u.users_seq, u.name, u.id, u.role, u.hire_date, u.dept_seq, u.rank_seq, u.is_hr_manager, u.resign_date, u.update_at, d.dept_name, d.auth_group, r.rank_name, CASE u.status WHEN 'ACTIVE' THEN '재직' WHEN 'INACTIVE' THEN '휴직' WHEN 'RETIRE' THEN '퇴사' END as status FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq LEFT JOIN "RANK" r ON u.rank_seq = r.rank_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')
ORDER BY u.users_seq ) a ) WHERE rn BETWEEN #{start} AND #{end}

SELECT COUNT(*) FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')

SELECT COUNT(*) FROM users u LEFT JOIN departments d ON u.dept_seq = d.dept_seq
AND u.status = #{status}
AND u.users_seq = #{keyword}
AND (u.name LIKE '%' || #{keyword} || '%' OR d.dept_name LIKE '%' || #{keyword} || '%')

mapper.update:
update users set 
	phone=#{phone}, email=#{email}, zonecode=#{zonecode}, address1=#{address1}, address2=#{address2} 
where id = #{id}

mapper.select:
SELECT COUNT(*) FROM (
    SELECT EMAIL FROM USERS WHERE ID != #{id}
    UNION
    SELECT EMAIL FROM SIGNUP WHERE STATUS IN ('PENDING', 'APPROVED')
) WHERE EMAIL = #{email}

	select *
    from (
        select u.*
        from users u
        join departments d on u.dept_seq = d.dept_seq
        where u.rank_seq = #{approver_rank_seq}
        and (
            u.dept_seq = #{dept_seq}
            or d.dept_seq = (select parent_dept_seq from departments where dept_seq = #{dept_seq})
        )
        and u.users_seq != #{drafter_seq}
    )
    where rownum = 1

	select *
	from (
        select u.*
        from users u
        where u.rank_seq = #{approver_rank_seq}
        and u.dept_seq = #{target_dept_seq}
        and u.users_seq != #{drafter_seq}
    )
    where rownum = 1
